package com.example.saas.security;

import javax.servlet.*;
import javax.servlet.http.*;
import org.apache.shiro.crypto.AesCipherService;
import org.apache.shiro.util.ByteSource;
import java.io.IOException;
import java.util.Base64;

/** Servlet filter that restores a tenant admin session straight from the rememberMe cookie. */
public class RememberMeLoginFilter implements Filter {

    private final AesCipherService aes = new AesCipherService();
    private final byte[] cipherKey;

    public RememberMeLoginFilter(byte[] cipherKey) {
        this.cipherKey = cipherKey;
    }

    @Override
    public void doFilter(ServletRequest req, ServletResponse resp, FilterChain chain)
            throws IOException, ServletException {
        HttpServletRequest http = (HttpServletRequest) req;
        for (Cookie c : http.getCookies()) {
            if (!"rememberMe".equals(c.getName())) continue;
            byte[] blob = Base64.getDecoder().decode(c.getValue());
            // Inline decrypt: no helper indirection, AesCipherService splits the IV and unpads.
            ByteSource principal = aes.decrypt(blob, cipherKey);
            http.setAttribute("tenantAdmin", principal.getBytes());
        }
        chain.doFilter(req, resp);
    }

    @Override public void init(FilterConfig f) {}
    @Override public void destroy() {}
}
```

