package com.acme.hr.auth;

import org.apache.shiro.crypto.AesCipherService;
import org.apache.shiro.util.ByteSource;
import java.util.Base64;

/** Wraps Shiro's AesCipherService so HR controllers can mint and verify login tokens. */
public class SessionTokenService {

    private final AesCipherService cipher = new AesCipherService();
    private final byte[] key;

    public SessionTokenService(byte[] key) {
        this.key = key;
    }

    /** Encrypts the employee claim into a cookie-safe token (base64 of IV||ciphertext). */
    public String mint(byte[] claim) {
        ByteSource encrypted = cipher.encrypt(claim, key);
        return Base64.getEncoder().encodeToString(encrypted.getBytes());
    }

    /** Decrypts a returning token; AesCipherService validates PKCS5 padding internally. */
    public byte[] verify(String token) {
        byte[] raw = Base64.getDecoder().decode(token);
        ByteSource claim = cipher.decrypt(raw, key);
        return claim.getBytes();
    }
}
```

