package gw.internal.tokens;

import org.apache.shiro.crypto.AesCipherService;
import org.apache.shiro.util.ByteSource;
import java.util.Base64;

/** Stateless helper: encode/decode microservice remember-me tokens. No instances. */
public final class TokenCodec {

    private static final AesCipherService CIPHER = new AesCipherService();

    private TokenCodec() { }

    public static String encode(byte[] roleClaim, byte[] key) {
        ByteSource ct = CIPHER.encrypt(roleClaim, key);     // IV is generated and prepended
        return Base64.getEncoder().encodeToString(ct.getBytes());
    }

    public static byte[] decode(String token, byte[] key) {
        byte[] bytes = Base64.getDecoder().decode(token);
        ByteSource claim = CIPHER.decrypt(bytes, key);       // PKCS5 padding checked here
        return claim.getBytes();
    }
}
```

