package edu.lms.security;

import org.apache.shiro.crypto.AesCipherService;
import org.apache.shiro.util.ByteSource;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import java.util.Base64;

/** Spring component that encrypts/decrypts the LMS persistent-login cookie. */
@Component
public class RememberMeCookieCodec {

    private final AesCipherService cipher;
    private final byte[] key;

    public RememberMeCookieCodec(@Value("${lms.remember.key}") byte[] key) {
        this.key = key;
        this.cipher = new CipherBuilder().mode("CBC").padding("PKCS5").build();
    }

    public String write(byte[] enrollment) {
        return Base64.getEncoder().encodeToString(cipher.encrypt(enrollment, key).getBytes());
    }

    public byte[] read(String cookie) {
        ByteSource claim = cipher.decrypt(Base64.getDecoder().decode(cookie), key);
        return claim.getBytes();
    }

    /** Tiny builder around Shiro's service (CBC + PKCS5 are the AesCipherService defaults). */
    static final class CipherBuilder {
        private String mode = "CBC", padding = "PKCS5";
        CipherBuilder mode(String m) { this.mode = m; return this; }
        CipherBuilder padding(String p) { this.padding = p; return this; }
        AesCipherService build() { return new AesCipherService(); }
    }
}
```

